// // This module implements a 32-bit wide, 2-to-1 demultiplexer. When the select signal `sel` is LOW (0), the output `out` is assigned the value of `in2`. When `sel` is HIGH (1), `out` takes the value of `in1`.
module top_module(in1,in2,sel,out);input [31:0] in1,in2;
    input sel;
    output [31:0] out;

    assign out = (sel == 0) ? in1 : in2;
endmodule
